package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;
    private JsonObject jsonObject;

    @BeforeEach
    public void setUp() {
        jsonObject = new JsonObject();
        jsonObject.addProperty("key", "value");
        jsonTreeReader = new JsonTreeReader(jsonObject);
    }

    @Test
    public void testEndObject_NormalFlow() throws Exception {
        // Spy on jsonTreeReader
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Use reflection to override private expect method call by invoking a no-op instead of stubbing
        // We cannot stub private methods with Mockito directly

        // Initialize internal state to simulate being inside an object
        setField(spyReader, "stackSize", 2);
        Object[] stack = new Object[32];
        stack[0] = new Object(); // something on stack
        stack[1] = mock(java.util.Iterator.class); // iterator on top of stack
        setField(spyReader, "stack", stack);

        String[] pathNames = new String[32];
        pathNames[1] = "someName";
        setField(spyReader, "pathNames", pathNames);

        int[] pathIndices = new int[32];
        pathIndices[0] = 0;
        pathIndices[1] = 5;
        setField(spyReader, "pathIndices", pathIndices);

        // Because expect is private and cannot be stubbed, we override it by reflection:
        // Replace expect with a no-op via reflection hack: temporarily replace it with a no-op method
        // But Java does not support method replacement at runtime easily.
        // Instead, we can invoke endObject via reflection, but before that, override expect by subclassing:

        JsonTreeReader testReader = new JsonTreeReader(jsonObject) {
            @Override
            protected void expect(JsonToken expected) {
                // do nothing
            }
        };

        // Copy internal state from spyReader to testReader
        copyInternalState(spyReader, testReader);

        testReader.endObject();

        // Verify pathNames[stackSize - 1] is null
        String[] updatedPathNames = (String[]) getField(testReader, "pathNames");
        assertNull(updatedPathNames[1]);

        // Verify stackSize decreased by 2
        int updatedStackSize = (int) getField(testReader, "stackSize");
        assertEquals(0, updatedStackSize);

        // Verify pathIndices[stackSize - 1] incremented (stackSize > 0 condition)
        // Since after popStack twice stackSize is 0, no increment should happen
        int[] updatedPathIndices = (int[]) getField(testReader, "pathIndices");
        assertEquals(0, updatedPathIndices[0]);
        assertEquals(5, updatedPathIndices[1]);
    }

    @Test
    public void testEndObject_PathIndicesIncrementedWhenStackSizeGreaterThanZero() throws Exception {
        JsonTreeReader spyReader = spy(jsonTreeReader);

        JsonTreeReader testReader = new JsonTreeReader(jsonObject) {
            @Override
            protected void expect(JsonToken expected) {
                // do nothing
            }
        };

        // Setup stackSize = 3, so after popping twice it will be 1 (still > 0)
        setField(spyReader, "stackSize", 3);
        Object[] stack = new Object[32];
        stack[0] = new Object();
        stack[1] = mock(java.util.Iterator.class);
        stack[2] = new Object();
        setField(spyReader, "stack", stack);

        String[] pathNames = new String[32];
        pathNames[2] = "lastName";
        setField(spyReader, "pathNames", pathNames);

        int[] pathIndices = new int[32];
        pathIndices[0] = 1;
        pathIndices[1] = 2;
        pathIndices[2] = 3;
        setField(spyReader, "pathIndices", pathIndices);

        // Copy internal state from spyReader to testReader
        copyInternalState(spyReader, testReader);

        testReader.endObject();

        // After popping twice, stackSize should be 1
        int updatedStackSize = (int) getField(testReader, "stackSize");
        assertEquals(1, updatedStackSize);

        // pathNames[stackSize - 1] should be null
        String[] updatedPathNames = (String[]) getField(testReader, "pathNames");
        assertNull(updatedPathNames[0]);

        // pathIndices[stackSize - 1] should be incremented by 1
        int[] updatedPathIndices = (int[]) getField(testReader, "pathIndices");
        assertEquals(2, updatedPathIndices[0]); // incremented from 1 to 2
        assertEquals(2, updatedPathIndices[1]);
        assertEquals(3, updatedPathIndices[2]);
    }

    // Helper method to set private fields via reflection
    private void setField(Object target, String fieldName, Object value) {
        try {
            var field = JsonTreeReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            field.set(target, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Helper method to get private fields via reflection
    private Object getField(Object target, String fieldName) {
        try {
            var field = JsonTreeReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.get(target);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Helper method to copy internal state fields from one JsonTreeReader to another
    private void copyInternalState(JsonTreeReader from, JsonTreeReader to) {
        setField(to, "stackSize", getField(from, "stackSize"));
        setField(to, "stack", getField(from, "stack"));
        setField(to, "pathNames", getField(from, "pathNames"));
        setField(to, "pathIndices", getField(from, "pathIndices"));
    }
}
